//#region src/lib/BaseEmojiPlugin.ts
const BaseEmojiInputPlugin = createSlatePlugin({
	key: KEYS.emojiInput,
	editOnly: true,
	node: {
		isElement: true,
		isInline: true,
		isVoid: true
	}
});
const BaseEmojiPlugin = createTSlatePlugin({
	key: KEYS.emoji,
	editOnly: true,
	options: {
		data: DEFAULT_EMOJI_LIBRARY,
		trigger: ":",
		triggerPreviousCharPattern: /^\s?$/,
		createComboboxInput: () => ({
			children: [{ text: "" }],
			type: KEYS.emojiInput
		}),
		createEmojiNode: ({ skins }) => ({ text: skins[0].native })
	},
	plugins: [BaseEmojiInputPlugin]
}).overrideEditor(withTriggerCombobox);

//#endregion
//#region src/lib/transforms/insertEmoji.ts
const insertEmoji = (editor, emoji) => {
	const { createEmojiNode } = editor.getOptions(BaseEmojiPlugin);
	const emojiNode = createEmojiNode(emoji);
	editor.tf.insertNodes(emojiNode);
};

